class RosterPlayer {
  final String name;
  final String? number;
  final String? position;
  final String year;
  final String hometown;
  final String? photoUrl;
  final String? highSchool;
  final String? major;
  final String? height;
  final String? weight;
  final String? handedness;
  final String? clubTeam;
  final Map<String, String>? stats;

  const RosterPlayer({
    required this.name,
    this.number,
    this.position,
    required this.year,
    required this.hometown,
    this.photoUrl,
    this.highSchool,
    this.major,
    this.height,
    this.weight,
    this.handedness,
    this.clubTeam,
    this.stats,
  });
}

